var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`EVELYN_STREGA_NULL_NULL`,text:{KOREA:`계약이라...... 그런 단어는 별로 낭만적이지 않은데.`,JPN:`契約ね……あまりロマンチックな言葉ではないわね。`,ENG:`A contract... That doesn't sound romantic at all.`,TWN:`契約……這個詞一點都不浪漫。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EVELYN_STREGA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`EVELYN_STREGA_NULL_NULL`,text:{KOREA:`후후, 그렇게 고집을 부리면 어쩔 수 없네.`,JPN:`ふふ、どうしてもしてほしいの？　まったく、仕方がないんだから。`,ENG:`Hah hah. Okay, if you insist on calling it that, then sure.`,TWN:`呵呵，既然你這麼執著，那也沒辦法呢。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EVELYN_STREGA_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`EVELYN_STREGA_NULL_NULL`,text:{KOREA:`그렇게 무뚝뚝한 당신을 조금씩 가르쳐가는 것도 소소한 즐거움이니까.`,JPN:`そんなヤボなあなたに、少しずつ手ほどきをしていくのも、ささやかな楽しみだから。`,ENG:`There's fun in changing you a little bit at a time.`,TWN:`能一點一點地調教這麼遲鈍的你，也是種小小的樂趣呢。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EVELYN_STREGA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`EVELYN_STREGA_NULL_NULL`,text:{KOREA:`응? 내가 스트레가에서 일하는 진짜 이유를 알려달라고?`,JPN:`えっ？　私がストレガで働いている本当の理由を教えてほしい？`,ENG:`Excuse me? You want to know the real reason why I work at Strega?`,TWN:`嗯？要我告訴你，我在史特雷加工作的真正理由？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EVELYN_STREGA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`EVELYN_STREGA_NULL_NULL`,text:{KOREA:`물론, 이 종신계약엔 비밀함구도 포함이니까. 사장님이 원한다면 전부 가르쳐 줄 의향은 있어.`,JPN:`もちろん、この終身契約には秘密に関する条項もあるんだから、
社長が望むなら教えるのもやぶさかではないわ。`,ENG:`Sure, since this lifetime contract includes a confidentiality agreement, I'm willing to divulge all the information you want.`,TWN:`當然，這份終身契約包含了保密條款。但如果老闆想知道，我願意全部告訴您。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EVELYN_STREGA_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`EVELYN_STREGA_NULL_NULL`,text:{KOREA:`하지만 조심해줘. 호기심에 못 이겨 여자의 비밀을 들추는 순간 그 매력도 사라지는 법이거든.`,JPN:`でも、気をつけてね。好奇心に駆られて女の秘密を暴いてしまったら、魅了の魔法はたちまち解けてしまうものなの。`,ENG:`But before I do, I want you to know that what makes us women so attractive is the secrets that we keep.`,TWN:`但是請小心。當您敗給了好奇心，揭開女人秘密的那一刻，她的魅力就會消失無蹤。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EVELYN_STREGA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}}];export{e as default};